"""Golden-file regression tests over the dataset. Generated by agent-eval-scaffold."""

from __future__ import annotations

import json
from pathlib import Path

import pytest

from harness import normalize, run_case

EVALS_DIR = Path(__file__).resolve().parent
CASES = [
    json.loads(line)
    for line in (EVALS_DIR / "datasets" / "smoke.jsonl").read_text().splitlines()
    if line.strip()
]


@pytest.mark.parametrize("case", CASES, ids=[c["id"] for c in CASES])
def test_golden(case, request):
    result = normalize(run_case(case))
    golden_path = EVALS_DIR / "golden" / f"{case['id']}.json"

    if request.config.getoption("--update-golden"):
        golden_path.parent.mkdir(exist_ok=True)
        golden_path.write_text(json.dumps(result, indent=2, sort_keys=True) + "\n")

    assert golden_path.exists(), (
        f"no golden for {case['id']}; seed it with: pytest evals/ --update-golden"
    )
    golden = json.loads(golden_path.read_text())
    assert result == golden, (
        f"output drifted from golden {golden_path.name}; if the change is "
        "intentional rerun with --update-golden and commit the diff"
    )

    if "expected" in case:
        assert case["expected"] in json.dumps(result), (
            f"expected substring {case['expected']!r} missing from result"
        )
